import React from "react";

const Certifications = () => {
  return (
    <div className="section-container">
      <h2 className="section-title">Certifications</h2>
      <div className="card reveal stagger">
        <ul className="list">
        <li>Autodesk Certified User – AutoCAD (May 2025).

        </li>
        <li>Python Certification – Neural Gen-AI Networks (Aug 2025).
            
        </li>
        <li>Prompt Engineering – Neural Gen-AI Networks (Oct 2025).</li>
        <li>
          NPTEL (IIT Roorkee): Fundamentals of Object-Oriented Programming –
          Elite Certificate (Apr 2025).
        </li>
        <li>
          NPTEL (IIT Kharagpur): Database Management System (Sep 2025).
        </li>
        </ul>
      </div>
    </div>
  );
};

export default Certifications;
